class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        def is_palindrome(s: str) -> bool:
            return s == s[::-1]

        n = len(a)
        for i in range(n + 1):
            if is_palindrome(a[:i] + b[i:]):
                return True
            if is_palindrome(b[:i] + a[i:]):
                return True
        return False
